# dashboard.html loaded per-request below

@app.route('/login', methods=['GET','POST'])
def login():
    error = None
    if request.method == 'POST':
        u = request.form.get('username','').strip()
        p = request.form.get('password','').strip()
        user = USERS.get(u)
        if user and user['password'] == p:
            session['user'] = u
            session['role'] = user['role']
            return redirect(url_for('dashboard'))
        error = "Invalid username or password"
    return render_template_string(LOGIN_HTML, logo=LOGO_B64, error=error)

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

@app.route('/')
def index():
    if 'user' not in session:
        return redirect(url_for('login'))
    return redirect(url_for('dashboard'))

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    dash_path = os.path.join(os.path.dirname(__file__), 'dashboard.html')
    with open(dash_path) as f:
        html = f.read()
    return render_template_string(html, logo=LOGO_B64,
                                  role=session['role'], user=session['user'])

@app.route('/api/data')
def api_data():
    if 'user' not in session:
        return jsonify(error='Unauthorized'), 401
    data = load_data()
    if not data:
        return jsonify(None)
    role = session['role']
    if role == 'investor':
        return jsonify({
            "uploaded_at":    data["uploaded_at"],
            "filename":       data["filename"],
            "meta":           data["meta"],
            "overall_summary": data["overall_summary"],
            "investment":     data.get("investment", {}),
        })
    return jsonify(data)

@app.route('/process', methods=['POST'])
def process():
    if 'user' not in session or session['role'] != 'admin':
        return jsonify(error='Unauthorized'), 401
    if 'file' not in request.files:
        return jsonify(error='No file uploaded'), 400
    f = request.files['file']
    if not f.filename.endswith('.xlsx'):
        return jsonify(error='Must be an .xlsx file'), 400

    with tempfile.TemporaryDirectory() as tmp:
        src = os.path.join(tmp, 'input.xlsx')
        dst = os.path.join(tmp, 'output.xlsx')
        f.save(src)
        try:
            run_fifo(src, dst)
            result = extract(dst)
            print(f"[DEBUG] extract returned {len(result)} values", flush=True)
            if len(result) == 5:
                overall_summary, inventory, fifo_rows, meta, investment = result
                print(f"[DEBUG] investment keys: {list(investment.keys())}", flush=True)
                print(f"[DEBUG] commits: {len(investment.get('commits',[]))}", flush=True)
            else:
                overall_summary, inventory, fifo_rows, meta = result
                investment = {}
                print("[DEBUG] OLD extract - no investment data", flush=True)
            save_data(f.filename, overall_summary, inventory, fifo_rows, meta, investment)
            print("[DEBUG] save_data completed", flush=True)
        except Exception as e:
            return jsonify(error=str(e)), 500
        with open(dst, 'rb') as fh:
            data = fh.read()

    return Response(data,
        mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        headers={'Content-Disposition': f'attachment; filename=FIFO_Output.xlsx'})

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=5000)
